import React, { useState, useCallback } from 'react';
import Header from './components/Header';
import ImageCapture from './components/ImageCapture';
import Evaluating from './components/Evaluating';
import Result from './components/Result';
import ApiKeyInput from './components/ApiKeyInput';
import './App.css';

// App states: idle, preview, evaluating, result
function App() {
  const [apiKey, setApiKey] = useState(localStorage.getItem('claude_api_key') || '');
  const [image, setImage] = useState(null);        // { file, preview }
  const [result, setResult] = useState(null);       // { isHotdog: bool }
  const [appState, setAppState] = useState('idle'); // idle | preview | evaluating | result
  const [error, setError] = useState(null);
  const [showSettings, setShowSettings] = useState(false);

  const handleApiKeySave = useCallback((key) => {
    setApiKey(key);
    localStorage.setItem('claude_api_key', key);
    setShowSettings(false);
  }, []);

  const handleClearApiKey = useCallback(() => {
    setApiKey('');
    localStorage.removeItem('claude_api_key');
  }, []);

  const handleImageSelect = useCallback((file) => {
    const preview = URL.createObjectURL(file);
    setImage({ file, preview });
    setResult(null);
    setError(null);
    setAppState('preview');
  }, []);

  const classifyImage = useCallback(async (imgOverride) => {
    const img = imgOverride || image;
    if (!img || !apiKey) return;

    setAppState('evaluating');
    setError(null);

    try {
      const base64 = await new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result.split(',')[1]);
        reader.onerror = reject;
        reader.readAsDataURL(img.file);
      });

      const mediaType = img.file.type || 'image/jpeg';

      const response = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 100,
          messages: [
            {
              role: 'user',
              content: [
                {
                  type: 'image',
                  source: {
                    type: 'base64',
                    media_type: mediaType,
                    data: base64,
                  },
                },
                {
                  type: 'text',
                  text: 'You are the "Not Hotdog" classifier from the TV show Silicon Valley. Look at this image and determine if it contains a hotdog (including hot dogs in buns, bare frankfurters, sausages that are clearly hotdogs). Respond with ONLY valid JSON, no other text: {"isHotdog": true/false}',
                },
              ],
            },
          ],
        }),
      });

      if (!response.ok) {
        const errData = await response.json().catch(() => ({}));
        throw new Error(errData?.error?.message || `API error: ${response.status}`);
      }

      const data = await response.json();
      const text = data.content?.[0]?.text || '';

      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (!jsonMatch) throw new Error('Unexpected response format');

      const parsed = JSON.parse(jsonMatch[0]);
      setResult({ isHotdog: parsed.isHotdog });
      setAppState('result');
    } catch (err) {
      setError(err.message);
      setAppState('preview');
    }
  }, [image, apiKey]);

  const handleCameraCapture = useCallback((file) => {
    const preview = URL.createObjectURL(file);
    const newImage = { file, preview };
    setImage(newImage);
    setResult(null);
    setError(null);
    setAppState('evaluating');
    // Small delay then classify
    setTimeout(() => classifyImage(newImage), 150);
  }, [classifyImage]);

  const handleReset = useCallback(() => {
    if (image?.preview) URL.revokeObjectURL(image.preview);
    setImage(null);
    setResult(null);
    setError(null);
    setAppState('idle');
  }, [image]);

  // No API key — show setup
  if (!apiKey || showSettings) {
    return (
      <div className="app">
        <Header />
        <main className="app-main">
          <ApiKeyInput
            onSave={handleApiKeySave}
            onClear={handleClearApiKey}
            hasExistingKey={!!apiKey}
            onCancel={() => setShowSettings(false)}
          />
        </main>
      </div>
    );
  }

  return (
    <div className="app">
      {/* Idle or Preview — show capture UI */}
      {(appState === 'idle' || appState === 'preview') && (
        <>
          <Header onSettingsClick={() => setShowSettings(true)} />
          <main className="app-main">
            <ImageCapture
              onImageSelect={handleImageSelect}
              onCameraCapture={handleCameraCapture}
              preview={image?.preview}
              onClassify={() => classifyImage()}
              appState={appState}
            />
            {error && (
              <div className="error-banner">
                <span>⚠</span> {error}
              </div>
            )}
          </main>
        </>
      )}

      {/* Evaluating — fullscreen image with spinner */}
      {appState === 'evaluating' && image && (
        <Evaluating preview={image.preview} />
      )}

      {/* Result — fullscreen image with verdict banner */}
      {appState === 'result' && image && result && (
        <Result
          preview={image.preview}
          isHotdog={result.isHotdog}
          onReset={handleReset}
        />
      )}
    </div>
  );
}

export default App;
